---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

import NavigationMenuViewport from "./navigation-menu-viewport.astro"

interface Props extends HTMLAttributes<"nav"> {
  viewport?: boolean
  delayOpen?: number
  delayClose?: number
  openOnFocus?: boolean
}

const {
  class: className = "",
  viewport = true,
  delayOpen = 0,
  delayClose = 50,
  openOnFocus,
  ...props
} = Astro.props
---

<nav
  {...props}
  data-slot="navigation-menu"
  data-viewport={viewport}
  data-delay-open={delayOpen}
  data-delay-close={delayClose}
  data-open-on-focus={openOnFocus}
  class={cn(
    "group/navigation-menu relative flex max-w-max flex-1 items-center justify-center",
    className
  )}
>
  <slot />
  {viewport && <NavigationMenuViewport />}
</nav>

<script>
  import { createNavigationMenu } from "@data-slot/navigation-menu"

  document
    .querySelectorAll('[data-slot="navigation-menu"]')
    .forEach((el) => createNavigationMenu(el))
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = {
  class?: string
  align?: "start" | "center" | "end"
  alignOffset?: number
  side?: "top" | "bottom"
  sideOffset?: number
} & HTMLAttributes<"div">

const {
  class: className = "",
  align = "start",
  alignOffset = 0,
  side = "bottom",
  sideOffset = 4,
  ...props
} = Astro.props

// Custom motion tuning for @data-slot/navigation-menu.
// Intentionally differs from shadcn/bejamas to keep transitions smooth in this Astro implementation.
---

<div
  {...props}
  data-slot="navigation-menu-content"
  data-align={align}
  data-align-offset={alignOffset}
  data-side={side}
  data-side-offset={sideOffset}
  hidden
  class={cn(
    "data-starting-style:pointer-events-none data-starting-style:opacity-0 data-ending-style:opacity-0",
    "data-[motion=from-right]:animate-in data-[motion=from-right]:fade-in-0 data-[motion=from-right]:slide-in-from-right-2",
    "data-[motion=from-left]:animate-in data-[motion=from-left]:fade-in-0 data-[motion=from-left]:slide-in-from-left-2",
    "data-[motion=to-right]:animate-out data-[motion=to-right]:fade-out-0 data-[motion=to-right]:slide-out-to-right-2",
    "data-[motion=to-left]:animate-out data-[motion=to-left]:fade-out-0 data-[motion=to-left]:slide-out-to-left-2",
    "duration-200 ease-out",
    "absolute",
    className
  )}
>
  <slot />
</div>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"li"> {
  value: string
}

const { class: className, value, ...props } = Astro.props
---

<li
  data-slot="navigation-menu-item"
  data-value={value}
  class={cn("relative", className)}
  {...props}
>
  <slot />
</li>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"a"> {
  active?: boolean
}

const { class: className, active, ...props } = Astro.props
---

<a
  data-slot="navigation-menu-link"
  class={cn(
    "data-[active=true]:focus:bg-muted data-[active=true]:hover:bg-muted data-[active=true]:bg-muted/50 focus-visible:ring-ring/50 hover:bg-muted focus:bg-muted flex items-center gap-1.5 rounded-sm p-2 text-sm transition-all outline-none focus-visible:ring-3 focus-visible:outline-1 [&_svg:not([class*='size-'])]:size-4",
    className
  )}
  {...props}
>
  <slot />
</a>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"ul"> {}

const { class: className, ...props } = Astro.props
---

<ul
  data-slot="navigation-menu-list"
  class={cn(
    "group flex flex-1 list-none items-center justify-center gap-0",
    className
  )}
  {...props}
>
  <slot />
</ul>

import { cva } from "class-variance-authority"

const navigationMenuTriggerStyle = cva(
  "bg-background hover:bg-muted focus:bg-muted data-open:hover:bg-muted data-open:focus:bg-muted data-open:bg-muted/50 focus-visible:ring-ring/50 data-popup-open:bg-muted/50 data-popup-open:hover:bg-muted group/navigation-menu-trigger inline-flex h-9 w-max items-center justify-center rounded-md px-4 py-2 text-sm font-medium transition-all outline-none focus-visible:ring-3 focus-visible:outline-1 disabled:pointer-events-none disabled:opacity-50"
)

export default navigationMenuTriggerStyle
